local pauseBtn=mkBtn("Pause",0)
local stopBtn=mkBtn("Stop",95)
local playing=true
local cf=1
local last=os.clock()
local inv=1/fps
ei:WritePixels(Vector2.zero,Vector2.new(W,H),px[1])
pauseBtn.MouseButton1Click:Connect(function()
playing=not playing
pauseBtn.Text=playing and "Pause" or "Play"
if snd then if playing then snd:Resume()else snd:Pause()end end
end)
stopBtn.MouseButton1Click:Connect(function()
sg:Destroy()
